local dnadesign = require("dnadesign")
local mash = dnadesign.mash
local hash = dnadesign.hash
local genolib = dofile("lib/genolib/genolib.lua")

-- pUC19 sequence (placeholder - replace with actual sequence)
local pUC19 = ""
pUC19 = pUC19 .. pUC19 -- simulate circularity
--pUC19 = dnadesign.transform.reverse_complement(pUC19)

-- Create containment sketch for query
local hasher = hash.new_crc32()
local query_sketch = mash.new_containment_sketch(20, pUC19, hasher)

-- Screen all features with 85% threshold
print("Features found in pUC19 (>85% containment):")
print("--------------------------------------------")

for _, feature in ipairs(genolib.features) do
	    local score = mash.containment(feature.mash, query_sketch)
	    if score > 0.20 then
	        print(string.format("%.1f%%  %s (%s)", score * 100, feature.feature, feature.feature_type))
	end
end
